// Test file for decimal32 and decimal64 support
use arrow_array::*;
use arrow_schema::*;
use arrow_cast::cast;

#[test]
fn test_decimal32_array_creation() {
    // Test creating a Decimal32Array
    let values = vec![Some(12345), Some(-67890), None, Some(999999999)];
    let array = Decimal32Array::from(values);

    assert_eq!(array.len(), 4);
    assert_eq!(array.value(0), 12345);
    assert_eq!(array.value(1), -67890);
    assert!(array.is_null(2));
    assert_eq!(array.value(3), 999999999);
}

#[test]
fn test_decimal64_array_creation() {
    // Test creating a Decimal64Array
    let values = vec![Some(123456789012345), Some(-678901234567890), None];
    let array = Decimal64Array::from(values);

    assert_eq!(array.len(), 3);
    assert_eq!(array.value(0), 123456789012345);
    assert_eq!(array.value(1), -678901234567890);
    assert!(array.is_null(2));
}

#[test]
fn test_decimal32_type_metadata() {
    let precision = 9;
    let scale = 2;
    let data_type = DataType::Decimal32(precision, scale);

    match data_type {
        DataType::Decimal32(p, s) => {
            assert_eq!(p, precision);
            assert_eq!(s, scale);
        }
        _ => panic!("Expected Decimal32 type"),
    }
}

#[test]
fn test_decimal64_type_metadata() {
    let precision = 18;
    let scale = 6;
    let data_type = DataType::Decimal64(precision, scale);

    match data_type {
        DataType::Decimal64(p, s) => {
            assert_eq!(p, precision);
            assert_eq!(s, scale);
        }
        _ => panic!("Expected Decimal64 type"),
    }
}

#[test]
fn test_decimal32_to_decimal128_cast() {
    // Test casting from Decimal32 to Decimal128
    let values = vec![Some(12345), Some(-67890), None];
    let decimal32_array = Decimal32Array::from(values)
        .with_precision_and_scale(9, 2)
        .unwrap();

    let decimal128_array = cast(&decimal32_array, &DataType::Decimal128(18, 2)).unwrap();

    let decimal128_array = decimal128_array
        .as_any()
        .downcast_ref::<Decimal128Array>()
        .unwrap();

    assert_eq!(decimal128_array.len(), 3);
    assert_eq!(decimal128_array.value(0), 12345);
    assert_eq!(decimal128_array.value(1), -67890);
    assert!(decimal128_array.is_null(2));
}

#[test]
fn test_decimal64_to_decimal128_cast() {
    // Test casting from Decimal64 to Decimal128
    let values = vec![Some(123456789012345), Some(-678901234567890), None];
    let decimal64_array = Decimal64Array::from(values)
        .with_precision_and_scale(18, 6)
        .unwrap();

    let decimal128_array = cast(&decimal64_array, &DataType::Decimal128(38, 6)).unwrap();

    let decimal128_array = decimal128_array
        .as_any()
        .downcast_ref::<Decimal128Array>()
        .unwrap();

    assert_eq!(decimal128_array.len(), 3);
    assert_eq!(decimal128_array.value(0), 123456789012345);
    assert_eq!(decimal128_array.value(1), -678901234567890);
    assert!(decimal128_array.is_null(2));
}

#[test]
fn test_decimal128_to_decimal32_cast() {
    // Test casting from Decimal128 to Decimal32 (should work for small values)
    let values = vec![Some(12345i128), Some(-67890i128), None];
    let decimal128_array = Decimal128Array::from(values)
        .with_precision_and_scale(18, 2)
        .unwrap();

    let decimal32_array = cast(&decimal128_array, &DataType::Decimal32(9, 2)).unwrap();

    let decimal32_array = decimal32_array
