    assert_eq!(decimal32_array.value(0), 12345);
    assert_eq!(decimal32_array.value(1), -67890);
    assert!(decimal32_array.is_null(2));
}

#[test]
fn test_decimal128_to_decimal64_cast() {
    // Test casting from Decimal128 to Decimal64 (should work for small values)
    let values = vec![Some(123456789012345i128), Some(-678901234567890i128), None];
    let decimal128_array = Decimal128Array::from(values)
        .with_precision_and_scale(38, 6)
        .unwrap();

    let decimal64_array = cast(&decimal128_array, &DataType::Decimal64(18, 6)).unwrap();

    let decimal64_array = decimal64_array
        .as_any()
        .downcast_ref::<Decimal64Array>()
        .unwrap();

    assert_eq!(decimal64_array.len(), 3);
    assert_eq!(decimal64_array.value(0), 123456789012345);
    assert_eq!(decimal64_array.value(1), -678901234567890);
    assert!(decimal64_array.is_null(2));
