#[test]
fn test_int32_to_decimal32_cast() {
    // Test casting from Int32 to Decimal32
    let values = vec![Some(12345), Some(-67890), None];
    let int32_array = Int32Array::from(values);

    let decimal32_array = cast(&int32_array, &DataType::Decimal32(9, 2)).unwrap();

    let decimal32_array = decimal32_array
        .as_any()
        .downcast_ref::<Decimal32Array>()
        .unwrap();

    assert_eq!(decimal32_array.len(), 3);
    // Values should be multiplied by 10^2 (scale)
    assert_eq!(decimal32_array.value(0), 1234500);
    assert_eq!(decimal32_array.value(1), -6789000);
    assert!(decimal32_array.is_null(2));
