#[test]
fn test_cast_int32_to_decimal32() {
    let array = Int32Array::from(vec![Some(1), Some(2), Some(3), None, Some(5)]);
    let array = Arc::new(array) as ArrayRef;
    let output_type = DataType::Decimal32(7, 2);
    assert!(can_cast_types(array.data_type(), &output_type));
    let result = cast(&array, &output_type).unwrap();
    let decimal_array = result
        .as_any()
        .downcast_ref::<Decimal32Array>()
        .unwrap();
    assert_eq!(decimal_array.len(), 5);
    assert_eq!(decimal_array.value(0), 100);  // 1 * 10^2
    assert_eq!(decimal_array.value(1), 200);  // 2 * 10^2
    assert_eq!(decimal_array.value(2), 300);  // 3 * 10^2
    assert!(decimal_array.is_null(3));
    assert_eq!(decimal_array.value(4), 500);  // 5 * 10^2
}

